import java.util.*;

// Solution class to find all distinct substrings of a string
class Solution {
    // Function to count all distinct
    // substrings of a given string
    public Set<String> countDistinctSubstrings(String s) {
        // Set to store
        // distinct substrings
        Set<String> st = new HashSet<>();

        // Length of the
        // input string
        int n = s.length();

        // Iterate over each
        // character in the string
        for (int i = 0; i < n; i++) {
            // Initialize an empty string
            // to store the current substring
            StringBuilder str = new StringBuilder();

            // Iterate over the remaining characters 
            // in the string starting from index i
            for (int j = i; j < n; j++) {
                // Append the current
                // character to the substring
                str.append(s.charAt(j));

                // Insert the current
                // substring into the set
                st.add(str.toString());
            }
        }

        // Return the set containing
        // all distinct substrings
        return st;
    }
}

public class Main {
    public static void main(String[] args) {
        String s = "striver";
        System.out.println("Given String: " + s);

        Solution sol = new Solution();

        // Call the function to
        // count distinct substrings
        Set<String> substrings = sol.countDistinctSubstrings(s);

        int count = 0;

        // Print the distinct substrings
        System.out.println("Distinct Substrings:");
        for (String substr : substrings) {
            System.out.println(substr);
            count++;
        }

        // Count + 1 as we have to count
        // the empty string as well
        System.out.println("Number of distinct substrings: " + (count + 1));
    }
}

